link.script:
    jQuery(document).ready(function($) {
    // Open login modal
    $('#open-login-modal').on('click', function(e) {
        e.preventDefault();
        $('#login-modal').fadeIn(300);
    });

    // Close modal
    $('.close-modal').on('click', function() {
        $(this).closest('.modal').fadeOut();
        $('#login-form').show();
        $('#reset-form').hide();
        $('#reset-status').hide();
        $('#login-error').text('');
        $('#reset-error').text('');
    });

    // Toggle between login and reset password forms
    $('#show-reset-form').on('click', function(e) {
        e.preventDefault();
        $('#login-form').hide();
        $('#reset-form').show();

        $('input[type="submit"].btn-full-ac').val("Verifikasi");
    });

    $('#show-login-form').on('click', function(e) {
        e.preventDefault();
        $('#reset-form').hide();
        $('#login-form').show();

        $('input[type="submit"].btn-full-ac').val("Masuk");
    });

    // Toggle password visibility
    $('.toggle-password').on('click', function() {
        var input = $($(this).attr('toggle'));
        if (input.attr('type') == 'password') {
            input.attr('type', 'text');
            $(this).removeClass('fa-eye').addClass('fa-eye-slash');
        } else {
            input.attr('type', 'password');
            $(this).removeClass('fa-eye-slash').addClass('fa-eye');
        }
    });

    // AJAX login
    $('#loginform').on('submit', function(e) {
        e.preventDefault();

        var turnstileResponse = $('.cf-turnstile input[name="cf-turnstile-response"]').val();

        var data = {
            'action': 'ajaxlogin',
            'username': $('#user_login').val(),
            'password': $('#user_pass').val(),
            'rememberme': $('#rememberme').is(':checked') ? 1 : 0,
            'security': $('#loginsecurity').val(),
            'turnstile_response': turnstileResponse
        };

        $('#login-error').text(''); // Clear previous error message

        console.log(data);

        $('#btn-login').val("Tunggu Sebentar...");
        $('input[type="submit"].btn-full-ac').addClass("bg-disable-btn");
        $('input[type="submit"]#btn-login').css("background-color", "#191919 !important");


        $.post(ajxObj.ajax_url, data, function(response) {
            var result = JSON.parse(response);
            if (result.loggedin) {
                $('#login-error').css('color', 'green').text(result.message);
                setTimeout(function() {
                    window.location.reload();
                }, 2000);
            } else {
                $('#login-error').css('color', 'red').html(result.message);
                $('#btn-login').val("Masuk");
                $('.btn-full-ac').removeClass("bg-disable-btn");

                turnstile.reset();
            }
        }).fail(function(xhr, status, error) {
            $('#login-error').css('color', 'red').html('An error occurred: ' + status + ' - ' + error);

            $('#btn-login').val("Masuk");
            $('.btn-full-ac').removeClass("bg-disable-btn");

            turnstile.reset();
        });
    });

    // Function to refresh the Turnstile widget
    function refreshTurnstile() {
        $('.cf-turnstile').empty(); // Clear the existing widget
        turnstile.render('.cf-turnstile', {
            sitekey: '0x4AAAAAAAfy-B7aPNleEnAs'
        });
    }

    // AJAX reset password
    $('#resetform').on('submit', function(e) {
        e.preventDefault();
        var data = {
            'action': 'ajaxresetpassword',
            'username_or_email': $('#user_login_reset').val(),
            'security': $('#resetsecurity').val()
        };

        $('#reset-error').text(''); // Clear previous error message

        $('input[type="submit"].btn-full-ac').addClass("bg-disable-btn");
        $('#btn-reset').val("Tunggu Sebentar...");

        $.post(ajxObj.ajax_url, data, function(response) {
            var result = JSON.parse(response);
            $('#reset-error').text(result.message);
            if (result.reset) {
                // $('#reset-error').css('color', 'green').text(result.message);
                // setTimeout(function() {
                //     $('#reset-form').hide();
                //     $('#login-form').show();
                // }, 2000);

                $('#reset-form').hide();
                $('#reset-status').show();

            } else {
                $('#reset-error').css('color', 'red').text(result.message);

                $('input[type="submit"].btn-full-ac').removeClass("bg-disable-btn");
                $('#btn-reset').val("Verifikasi");
            }
        }).fail(function(xhr, status, error) {
            $('#reset-error').css('color', 'red').text('An error occurred: ' + status + ' - ' + error);

            $('input[type="submit"].btn-full-ac').removeClass("bg-disable-btn");
            $('#btn-reset').val("Verifikasi");
        });
    });

    // Toggle user dropdown menu
    $('#username').on('click', function() {
        $('#user-dropdown').toggle();
    });

    // Hide dropdown when clicking outside
    $(document).on('click', function(event) {
        if (!$(event.target).closest('#user-menu').length) {
            $('#user-dropdown').hide();
        }
    });
    if (window.location.hash === '#login') {
        $('#open-login-modal').click();
    }
    if (window.location.hash === '#forgot-password') {
        $('#open-login-modal').click();
        $('#show-reset-form').click();
    }
});

